TEST(PairingTest, OutOfOrderCalls) {
  boost::property_tree::ptree tree;

  setup(PRIVATE_KEY, PUBLIC_CERT);

  pair_session_t sess {};

  clientchallenge(sess, tree, "test");
  ASSERT_FALSE(tree.get<int>("root.paired") == 1);

  serverchallengeresp(sess, tree, "test");
  ASSERT_FALSE(tree.get<int>("root.paired") == 1);

  clientpairingsecret(sess, tree, "test");
  ASSERT_FALSE(tree.get<int>("root.paired") == 1);

  // This should work, it's the first time we call it
  sess.async_insert_pin.salt = "ff5dc6eda99339a8a0793e216c4257c4";
  getservercert(sess, tree, "test");
  ASSERT_TRUE(tree.get<int>("root.paired") == 1);

  // Calling it again should fail
  getservercert(sess, tree, "test");
  ASSERT_FALSE(tree.get<int>("root.paired") == 1);
}

TEST(PairingStateTest, ConcurrentFirstClientGrantIsAtomic) {
  const bool previous_fresh_state = config::sunshine.flags[config::flag::FRESH_STATE];
  config::sunshine.flags[config::flag::FRESH_STATE] = true;
  erase_all_clients();
  auto cleanup = util::fail_guard([&]() {
    erase_all_clients();
    config::sunshine.flags[config::flag::FRESH_STATE] = previous_fresh_state;
  });

  constexpr int client_count = 8;
  const auto &certificates = distinct_test_certificates();
  std::vector<std::jthread> clients;
  clients.reserve(client_count);
  for (int index = 0; index < client_count; ++index) {
    clients.emplace_back([index, &certificates]() {
      add_authorized_client_for_test("concurrent-" + std::to_string(index), certificates[index]);
    });
  }
  clients.clear();  // jthread destruction joins every insertion.

  const auto authorized = get_all_clients();
  ASSERT_EQ(authorized.size(), client_count);
  int full_control_clients = 0;
  int default_clients = 0;
  for (const auto &client : authorized) {
    const auto permission = client.at("perm").get<std::uint32_t>();
    full_control_clients += permission == static_cast<std::uint32_t>(crypto::PERM::_all);
    default_clients += permission == static_cast<std::uint32_t>(crypto::PERM::_default);
  }
  ASSERT_EQ(full_control_clients, 1);
  ASSERT_EQ(default_clients, client_count - 1);
  for (const auto &certificate : certificates) {
    ASSERT_TRUE(is_client_certificate_authorized(certificate));
  }
}

TEST(PairingStateTest, DuplicateCertificatePairingIsIdempotent) {
  const bool previous_fresh_state = config::sunshine.flags[config::flag::FRESH_STATE];
  config::sunshine.flags[config::flag::FRESH_STATE] = true;
  erase_all_clients();
  auto cleanup = util::fail_guard([&]() {
    erase_all_clients();
    config::sunshine.flags[config::flag::FRESH_STATE] = previous_fresh_state;
  });

  add_authorized_client_for_test("first-name", PUBLIC_CERT);
  const auto original = get_all_clients();
  ASSERT_EQ(original.size(), 1);

  // The same X.509 identity with different PEM whitespace is still the same client. Re-pairing
  // preserves the original UUID, name, permissions, and administrator settings.
  add_authorized_client_for_test("second-name", PUBLIC_CERT + "\n");
  const auto after_repair = get_all_clients();
  ASSERT_EQ(after_repair.size(), 1);
  EXPECT_EQ(after_repair.front(), original.front());
}

TEST(PairingStateTest, KeepAliveAuthorizationRefreshesAfterUpdateAndRevoke) {
  const bool previous_fresh_state = config::sunshine.flags[config::flag::FRESH_STATE];
  config::sunshine.flags[config::flag::FRESH_STATE] = true;
  erase_all_clients();
  auto cleanup = util::fail_guard([&]() {
    erase_all_clients();
    config::sunshine.flags[config::flag::FRESH_STATE] = previous_fresh_state;
  });

  add_authorized_client_for_test("before-update", PUBLIC_CERT);
  auto stale = get_authorized_client_for_test(PUBLIC_CERT);
  ASSERT_TRUE(stale);
  ASSERT_EQ(stale->perm, crypto::PERM::_all);

  ASSERT_TRUE(update_device_info(
    stale->uuid,
    "after-update",
    crypto::PERM::_no
  ));
  auto refreshed = refresh_authorized_client_for_test(stale);
  ASSERT_TRUE(refreshed);
  EXPECT_NE(refreshed.get(), stale.get());
  EXPECT_EQ(refreshed->name, "after-update");
  EXPECT_EQ(refreshed->perm, crypto::PERM::_no);

  ASSERT_TRUE(unpair_client(stale->uuid));
  EXPECT_FALSE(refresh_authorized_client_for_test(stale));
}

namespace {
  std::shared_ptr<stream::session_t> make_test_stream_session(
    std::uint32_t id,
    std::string uuid,
    std::string name,
    crypto::PERM permissions
  ) {
    stream::config_t stream_config {};
    rtsp_stream::launch_session_t launch_session {};
    launch_session.id = id;
    launch_session.unique_id = std::move(uuid);
    launch_session.device_name = std::move(name);
    launch_session.perm = permissions;
    launch_session.gcm_key.resize(16);
    launch_session.iv.resize(16);
    return stream::session::alloc(stream_config, launch_session);
  }
}  // namespace

TEST(PairingStateTest, UpdatesActiveSessionAndRejectsASecondSession) {
  const bool previous_fresh_state = config::sunshine.flags[config::flag::FRESH_STATE];
  config::sunshine.flags[config::flag::FRESH_STATE] = true;
  erase_all_clients();
  auto state_cleanup = util::fail_guard([&]() {
    erase_all_clients();
    config::sunshine.flags[config::flag::FRESH_STATE] = previous_fresh_state;
  });

  add_authorized_client_for_test("single-session", PUBLIC_CERT);
  const auto client = get_authorized_client_for_test(PUBLIC_CERT);
  ASSERT_TRUE(client);

  auto first = make_test_stream_session(1, client->uuid, "before", crypto::PERM::_default);
  auto second = make_test_stream_session(2, client->uuid, "before", crypto::PERM::_default);
  auto unrelated = make_test_stream_session(3, "unrelated", "other", crypto::PERM::_default);
  auto session_cleanup = util::fail_guard([&]() {
    rtsp_stream::remove_session_for_test(first);
  });
  ASSERT_TRUE(rtsp_stream::insert_session_for_test(first));
  EXPECT_FALSE(rtsp_stream::insert_session_for_test(second));
  EXPECT_FALSE(rtsp_stream::insert_session_for_test(unrelated));

  EXPECT_EQ(rtsp_stream::find_session(client->uuid), first);
  ASSERT_TRUE(rtsp_stream::active_session_uuid());
  EXPECT_EQ(*rtsp_stream::active_session_uuid(), client->uuid);
  ASSERT_TRUE(update_device_info(
    client->uuid,
    "after",
    crypto::PERM::_all
  ));

  EXPECT_EQ(stream::session::permissions(*first), crypto::PERM::_all);
  EXPECT_EQ(stream::session::client_name(*first), "after");
  EXPECT_EQ(stream::session::permissions(*second), crypto::PERM::_default);
  EXPECT_EQ(stream::session::client_name(*second), "before");
  EXPECT_EQ(stream::session::permissions(*unrelated), crypto::PERM::_default);
  EXPECT_EQ(stream::session::client_name(*unrelated), "other");

  // A launch authenticated before the update but inserted afterward must receive the latest
  // policy rather than the stale permission snapshot carried by its RTSP launch record.
  rtsp_stream::remove_session_for_test(first);
  auto late = make_test_stream_session(4, client->uuid, "stale", crypto::PERM::_default);
  ASSERT_TRUE(rtsp_stream::insert_session_for_test(late));
  auto late_cleanup = util::fail_guard([&]() {
    rtsp_stream::remove_session_for_test(late);
  });
  EXPECT_EQ(stream::session::permissions(*late), crypto::PERM::_all);
  EXPECT_EQ(stream::session::client_name(*late), "after");
}

TEST(PairingStateTest, RevokingViewStopsActiveSessionAndRejectsLateLaunch) {
  const bool previous_fresh_state = config::sunshine.flags[config::flag::FRESH_STATE];
  config::sunshine.flags[config::flag::FRESH_STATE] = true;
  erase_all_clients();
  auto state_cleanup = util::fail_guard([&]() {
    erase_all_clients();
    config::sunshine.flags[config::flag::FRESH_STATE] = previous_fresh_state;
  });

  add_authorized_client_for_test("revoked-client", PUBLIC_CERT);
  const auto client = get_authorized_client_for_test(PUBLIC_CERT);
  ASSERT_TRUE(client);

  auto first = make_test_stream_session(10, client->uuid, "before", crypto::PERM::_default);
  auto session_cleanup = util::fail_guard([&]() {
    rtsp_stream::remove_session_for_test(first);
  });
  ASSERT_TRUE(rtsp_stream::insert_session_for_test(first));

  stream::session::set_state_for_test(*first, stream::session::state_e::RUNNING);

  ASSERT_TRUE(update_device_info(
    client->uuid,
    "revoked-client",
    crypto::PERM::_no
  ));

  EXPECT_EQ(stream::session::state(*first), stream::session::state_e::STOPPING);
  EXPECT_EQ(stream::session::permissions(*first), crypto::PERM::_no);

  rtsp_stream::remove_session_for_test(first);
  auto late = make_test_stream_session(13, client->uuid, "stale", crypto::PERM::_all);
  EXPECT_FALSE(rtsp_stream::insert_session_for_test(late));
}

TEST(PairingStateTest, UnpairStopsActiveSessionAndRejectsLateLaunch) {
  const bool previous_fresh_state = config::sunshine.flags[config::flag::FRESH_STATE];
  config::sunshine.flags[config::flag::FRESH_STATE] = true;
  erase_all_clients();
  auto state_cleanup = util::fail_guard([&]() {
    erase_all_clients();
    config::sunshine.flags[config::flag::FRESH_STATE] = previous_fresh_state;
  });

  add_authorized_client_for_test("unpaired-client", PUBLIC_CERT);
  const auto client = get_authorized_client_for_test(PUBLIC_CERT);
  ASSERT_TRUE(client);

  auto first = make_test_stream_session(20, client->uuid, "before", crypto::PERM::_default);
  auto session_cleanup = util::fail_guard([&]() {
    rtsp_stream::remove_session_for_test(first);
  });
  ASSERT_TRUE(rtsp_stream::insert_session_for_test(first));

  stream::session::set_state_for_test(*first, stream::session::state_e::RUNNING);

  ASSERT_TRUE(unpair_client(client->uuid));
  EXPECT_EQ(stream::session::state(*first), stream::session::state_e::STOPPING);

  rtsp_stream::remove_session_for_test(first);
  auto late = make_test_stream_session(23, client->uuid, "stale", crypto::PERM::_all);
  EXPECT_FALSE(rtsp_stream::insert_session_for_test(late));
}

TEST(PairingStateTest, OlderRuntimePolicyCannotOverwriteNewerGeneration) {
  static std::atomic<std::uint64_t> next_generation {0};
  const auto newer_generation = next_generation.fetch_add(2, std::memory_order_relaxed) + 2;
  auto session = make_test_stream_session(
    30,
    "policy-generation-order",
    "initial",
    crypto::PERM::_default
  );
  auto cleanup = util::fail_guard([&]() {
    rtsp_stream::remove_session_for_test(session);
  });
  ASSERT_TRUE(rtsp_stream::insert_session_for_test(session));

  ASSERT_TRUE(rtsp_stream::publish_client_policy("policy-generation-order", newer_generation, "newer", crypto::PERM::_all, false));
  EXPECT_FALSE(rtsp_stream::publish_client_policy("policy-generation-order", newer_generation - 1, "older", crypto::PERM::_default, false));

  EXPECT_EQ(stream::session::permissions(*session), crypto::PERM::_all);
  EXPECT_EQ(stream::session::client_name(*session), "newer");
}

TEST(PairingStateTest, SessionWithoutViewPermissionIsRejectedWithoutRuntimeOverlay) {
  auto session = make_test_stream_session(
    31,
    "no-runtime-policy",
    "no-view",
    crypto::PERM::_no
  );
  EXPECT_FALSE(rtsp_stream::insert_session_for_test(session));
}

TEST(PairingStateTest, SessionRejectsDelayedOlderRuntimePolicy) {
  auto session = make_test_stream_session(
    32,
    "per-session-generation-order",
    "initial",
    crypto::PERM::_default
  );

  EXPECT_EQ(
    stream::session::update_client_policy(*session, 2, "newer", crypto::PERM::_all, false),
    stream::session::client_policy_result_e::updated
  );
  EXPECT_EQ(
    stream::session::update_client_policy(*session, 1, "older", crypto::PERM::_default, false),
    stream::session::client_policy_result_e::ignored
  );
  EXPECT_EQ(stream::session::permissions(*session), crypto::PERM::_all);
  EXPECT_EQ(stream::session::client_name(*session), "newer");
}

TEST(PairingStateTest, DelayedRevokeCannotStopSessionAfterNewerAllowPolicy) {
  static std::atomic<std::uint64_t> next_generation {0};
  const auto allow_generation = next_generation.fetch_add(2, std::memory_order_relaxed) + 2;
  const auto revoke_generation = allow_generation - 1;
  auto session = make_test_stream_session(
    33,
    "deferred-stop-generation-order",
    "initial",
    crypto::PERM::_all
  );
  auto cleanup = util::fail_guard([&]() {
    rtsp_stream::remove_session_for_test(session);
  });
  ASSERT_TRUE(rtsp_stream::insert_session_for_test(session));
  stream::session::set_state_for_test(*session, stream::session::state_e::RUNNING);

  auto delayed_revoke = rtsp_stream::stage_client_policy(
    "deferred-stop-generation-order",
    revoke_generation,
    "revoked",
    crypto::PERM::_no,
    true
  );
  ASSERT_TRUE(delayed_revoke.accepted);
  auto newer_allow = rtsp_stream::stage_client_policy(
    "deferred-stop-generation-order",
    allow_generation,
    "allowed",
    crypto::PERM::_all,
    false
  );
  ASSERT_TRUE(newer_allow.accepted);

  rtsp_stream::complete_client_policy(std::move(delayed_revoke));
  rtsp_stream::complete_client_policy(std::move(newer_allow));
  EXPECT_EQ(stream::session::state(*session), stream::session::state_e::RUNNING);
  EXPECT_EQ(stream::session::permissions(*session), crypto::PERM::_all);
  EXPECT_EQ(stream::session::client_name(*session), "allowed");
}

TEST(PairingStateTest, InvalidOtpAuthenticationDoesNotConsumeOtp) {
  constexpr std::string_view passphrase = "test-passphrase";
  constexpr std::string_view salt = "test-salt";
  const auto pin = request_otp(std::string(passphrase), "otp-client");
  ASSERT_FALSE(pin.empty());

  EXPECT_FALSE(authenticate_otp_for_test("invalid-authentication", std::string(salt)));

  const auto digest = util::hex(crypto::hash(pin + std::string(salt) + std::string(passphrase)), true);
  EXPECT_TRUE(authenticate_otp_for_test(std::string(digest.to_string_view()), std::string(salt)));
  EXPECT_FALSE(authenticate_otp_for_test(std::string(digest.to_string_view()), std::string(salt)));
}

TEST(PairingStateTest, BoundsUnauthenticatedPairingAndSerializesManualPin) {
  using admission = nvhttp::detail::pairing_admission_e;
  using nvhttp::detail::pairing_admission;

  EXPECT_EQ(pairing_admission(15, 16, false, false, false), admission::allowed);
  EXPECT_EQ(pairing_admission(16, 16, false, false, false), admission::capacity_reached);
  EXPECT_EQ(pairing_admission(16, 16, true, false, false), admission::allowed);
  EXPECT_EQ(pairing_admission(1, 16, false, true, true), admission::manual_pin_conflict);
  EXPECT_EQ(pairing_admission(1, 16, false, false, true), admission::allowed);
}
